/*
1~3,6~7(,8~10).
25~40pts.
*/
#include <bits/stdc++.h>
#define ull unsigned long long
using namespace std;

const int N=5e4+10;

int n,q,a[N],qu[N],hh,tt;
long long s[N],res[N];

inline long long cal(int x,int len){
	return s[x+len-1]-s[x-1];
}

int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		s[i]=s[i-1]+a[i];
	}
	scanf("%d",&q);
	while(q--){
		int l,r;
		scanf("%d%d",&l,&r);
		ull ans=0;
		for(int i=1;i<=n;i++)
			res[i]=-1e18;
		for(int i=l;i<=r;i++){
			hh=1,tt=0;
			for(int j=1;j<=n;j++){
				while(hh<=tt && qu[hh]+i-1<j)
					hh++;
				if(j+i-1<=n){
					while(hh<=tt && cal(qu[tt],i)<=cal(j,i))
						tt--;
					qu[++tt]=j;
				}
				res[j]=max(res[j],cal(qu[hh],i));
			}
		}
		for(int i=1;i<=n;i++){
			ull tmp=res[i];
			ans^=(ull)i*tmp;
		}
		printf("%llu\n",ans);
	}
	return 0;
}
